INSERT INTO programmes (id, slug, title, subtitle, audience, frequency, pass_mark, cert_on_completion, est_hours, total_modules, status) VALUES
  ('PROG-001', 'annual-caregiver-training', 'Annual Caregiver Training', 'Foundational training required for all Vitalis caregivers — Maryland RSA-aligned and BCHD contract-ready', 'All Vitalis caregivers', 'Annual', 80, true, 9, 12, 'in_production'),
  ('PROG-002', 'alzheimers-dementia-training', 'Alzheimer''s & Dementia Specialist Training', 'Advanced competency programme for caregivers supporting clients with Alzheimer''s disease and related dementias', 'Caregivers assigned to clients with dementia diagnoses; all caregivers recommended', 'Once on assignment + annual refresh', 80, true, 7, 7, 'not_started'),
  ('PROG-003', 'autism-spectrum-training', 'Autism Spectrum Specialist Training', 'Specialist training for caregivers supporting autistic children and young people in home settings', 'Caregivers assigned to autistic children; all caregivers working with paediatric clients recommended', 'Once on assignment + annual refresh', 80, true, 6, 6, 'not_started'),
  ('PROG-004', 'developmental-disability-training', 'Developmental Disability Specialist Training', 'Specialist training for caregivers supporting individuals with intellectual and developmental disabilities (IDD) in home settings', 'Caregivers assigned to clients with developmental disability diagnoses', 'Once on assignment + annual refresh', 80, true, 6.5, 6, 'not_started')
INSERT INTO tracks (id, programme_id, slug, title, description, colour_hex, order_index) VALUES
  ('PROG001-TRK-01', 'PROG-001', 'compliance-legal-foundations', 'Track 1 — Compliance & Legal Foundations', 'Maryland regulatory framework, client rights, and mandatory reporting obligations', '#A32D2D', 1),
  ('PROG001-TRK-02', 'PROG-001', 'safety-infection-control', 'Track 2 — Safety & Infection Control', 'Infection prevention, emergency preparedness, and home safety protocols', '#185FA5', 2),
  ('PROG001-TRK-03', 'PROG-001', 'personal-care-clinical-skills', 'Track 3 — Personal Care & Clinical Skills', 'ADL assistance techniques, nutrition, and safe care delivery', '#3B6D11', 3),
  ('PROG001-TRK-04', 'PROG-001', 'documentation-technology', 'Track 4 — Documentation & Technology', 'EVV compliance, AxisCare usage, and accurate visit documentation', '#BA7517', 4),
  ('PROG001-TRK-05', 'PROG-001', 'client-centred-care', 'Track 5 — Client-Centred Care', 'Communication, cultural competency, and cognitive support', '#534AB7', 5),
  ('PROG001-TRK-06', 'PROG-001', 'professional-development', 'Track 6 — Professional Development', 'Professionalism, boundaries, and caregiver wellbeing', '#0F6E56', 6),
  ('PROG002-TRK-01', 'PROG-002', 'understanding-dementia', 'Track 1 — Understanding Dementia', '', '#534AB7', 1),
  ('PROG002-TRK-02', 'PROG-002', 'behavioural-safety-dementia', 'Track 2 — Behaviour & Safety', '', '#A32D2D', 2),
  ('PROG002-TRK-03', 'PROG-002', 'activities-family-wellbeing-dementia', 'Track 3 — Activities, Family & Wellbeing', '', '#0F6E56', 3),
  ('PROG003-TRK-01', 'PROG-003', 'understanding-autism', 'Track 1 — Understanding Autism', '', '#534AB7', 1),
  ('PROG003-TRK-02', 'PROG-003', 'communication-behaviour-autism', 'Track 2 — Communication & Behaviour', '', '#185FA5', 2),
  ('PROG003-TRK-03', 'PROG-003', 'family-partnership-autism', 'Track 3 — Family Partnership & Daily Care', '', '#0F6E56', 3),
  ('PROG004-TRK-01', 'PROG-004', 'understanding-idd', 'Track 1 — Understanding IDD', '', '#534AB7', 1),
  ('PROG004-TRK-02', 'PROG-004', 'person-centred-daily-care-idd', 'Track 2 — Person-Centred Care & Daily Support', '', '#0F6E56', 2),
  ('PROG004-TRK-03', 'PROG-004', 'health-safety-idd', 'Track 3 — Health, Safety & Emergency Response', '', '#A32D2D', 3)
INSERT INTO courses (lms_module_id, programme_id, track_id, title, description, badge, order_index, estimated_minutes, objectives, category, thumbnail_color, status, pass_score) VALUES
  ('PROG001-MOD-001', 'PROG-001', 'PROG001-TRK-01', 'Maryland RSA Regulations & Caregiver Rights', 'COMAR 10.07.05 overview, RSA licensing framework, caregiver rights and employer obligations, what OHCQ inspects.', 'mandatory', 1, 40, ARRAY['Define what a Residential Service Agency (RSA) is under Maryland law','Identify the role of OHCQ in licensing and oversight','State at least four caregiver rights under Maryland law','List the core responsibilities required by COMAR 10.07.05','Describe the consequences of non-compliance for caregivers and the agency'], 'LMS', '#A32D2D', 'draft', 80),
  ('PROG001-MOD-002', 'PROG-001', 'PROG001-TRK-01', 'HIPAA & Client Confidentiality', 'Protected health information, what can and cannot be shared, social media risks, reporting breaches, client record handling.', 'mandatory', 2, 45, ARRAY['Define Protected Health Information (PHI) under HIPAA','Identify situations that constitute a HIPAA breach','Apply the minimum necessary standard to information sharing','Describe Vitalis''s internal procedure for reporting a breach','Explain social media risks specific to home care settings'], 'LMS', '#A32D2D', 'draft', 80),
  ('PROG001-MOD-003', 'PROG-001', 'PROG001-TRK-01', 'Abuse, Neglect & Exploitation Reporting', 'Maryland mandated reporter obligations, recognising signs of abuse and neglect, how to report to APS, Vitalis internal reporting procedure.', 'mandatory', 3, 45, ARRAY['Define abuse, neglect, and exploitation in the context of Maryland home care','Identify at least five physical and behavioural signs of abuse or neglect','Explain the mandated reporter obligation under Maryland law','Describe the process for reporting to Adult Protective Services (APS)','Follow Vitalis''s internal incident reporting procedure'], 'LMS', '#A32D2D', 'draft', 80),
  ('PROG001-MOD-004', 'PROG-001', 'PROG001-TRK-02', 'Infection Control & Universal Precautions', 'Standard precautions, PPE use, hand hygiene protocols, bloodborne pathogens, respiratory illness (COVID, flu), TB awareness.', 'mandatory', 1, 45, ARRAY['Apply standard precautions in all client care situations','Demonstrate correct PPE selection and use','Describe proper hand hygiene technique and frequency','Identify bloodborne pathogen exposure risks and response steps','Explain TB screening requirements for Vitalis caregivers'], 'LMS', '#185FA5', 'draft', 80),
  ('PROG001-MOD-005', 'PROG-001', 'PROG001-TRK-02', 'Home Safety & Emergency Preparedness', 'Fall prevention, fire safety, hazardous materials, emergency action plan, 911 protocol, natural disaster preparedness for Baltimore area.', 'mandatory', 2, 45, ARRAY['Identify at least six home hazards that create fall risk for clients','Follow the correct procedure for a fire emergency in a client''s home','Respond appropriately to a gas leak or hazardous material situation','Execute Vitalis''s emergency action plan steps correctly','Describe Baltimore-specific emergency preparedness considerations'], 'LMS', '#185FA5', 'draft', 80),
  ('PROG001-MOD-006', 'PROG-001', 'PROG001-TRK-03', 'Activities of Daily Living (ADLs)', 'Bathing, grooming, dressing, toileting assistance. Preserving dignity and client independence. Body mechanics to protect caregiver.', 'core', 1, 60, ARRAY['Assist clients with bathing and personal hygiene while preserving dignity','Apply safe body mechanics during transfers and mobility assistance','Support client independence at the appropriate level for each individual','Identify signs that a client''s ADL needs have changed','Document ADL assistance accurately in AxisCare'], 'LMS', '#3B6D11', 'draft', 80),
  ('PROG001-MOD-007', 'PROG-001', 'PROG001-TRK-03', 'Nutrition, Meal Prep & Feeding Assistance', 'Dietary restrictions, safe food handling, aspiration precautions, hydration monitoring, documenting food and fluid intake.', 'core', 2, 45, ARRAY['Identify common dietary restrictions and how to accommodate them','Apply safe food handling and storage procedures in a client''s home','Recognise aspiration risk and implement appropriate precautions','Monitor and document fluid intake accurately','Support clients who have difficulty chewing or swallowing'], 'LMS', '#3B6D11', 'draft', 80),
  ('PROG001-MOD-008', 'PROG-001', 'PROG001-TRK-04', 'Electronic Visit Verification (EVV) with AxisCare', 'How EVV works, clocking in/out correctly, what counts as a discrepancy, BCHD EVV compliance requirements, common errors and how to fix them.', 'core', 1, 45, ARRAY['Explain what EVV is and why it is required for BCHD-funded visits','Clock in and out correctly using the AxisCare app','Identify the five most common EVV discrepancy types','Follow the correct procedure for correcting an EVV error','Understand how EVV data links to Vitalis billing and BCHD compliance'], 'LMS', '#BA7517', 'draft', 80),
  ('PROG001-MOD-009', 'PROG-001', 'PROG001-TRK-04', 'Visit Documentation & Incident Reporting', 'Completing visit notes accurately, documenting ADLs and observations, incident report process, what and when to escalate to a supervisor.', 'core', 2, 45, ARRAY['Complete a visit note in AxisCare that meets Vitalis documentation standards','Document client observations using objective, factual language','Identify what constitutes a reportable incident','Submit an incident report within the required timeframe','Distinguish between incidents requiring immediate escalation vs routine reporting'], 'LMS', '#BA7517', 'draft', 80),
  ('PROG001-MOD-010', 'PROG-001', 'PROG001-TRK-05', 'Communication, Dignity & Cultural Competency', 'Active listening, person-centred language, non-verbal communication, serving Baltimore''s diverse communities, language access rights.', 'skill_building', 1, 45, ARRAY['Apply person-centred language in all client interactions','Use active listening techniques to understand client preferences and concerns','Respond appropriately to cultural differences in communication and care','Explain the Maryland Language Access Law and its implications for caregivers','Maintain client dignity in all personal care interactions'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG001-MOD-011', 'PROG-001', 'PROG001-TRK-05', 'Dementia, Cognitive Impairment & Behavioural Support', 'Stages of dementia, de-escalation techniques, redirection strategies, managing challenging behaviours, supporting family caregivers.', 'skill_building', 2, 45, ARRAY['Identify the stages of dementia and how they affect care needs','Apply redirection techniques to manage confusion or agitation','De-escalate challenging behaviours safely and calmly','Communicate effectively with clients who have limited verbal ability','Support family caregivers experiencing stress or burnout'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG001-MOD-012', 'PROG-001', 'PROG001-TRK-06', 'Professionalism, Boundaries & Self-Care', 'Professional conduct expectations, maintaining appropriate boundaries, caregiver burnout recognition, stress management and Vitalis support resources.', 'skill_building', 1, 30, ARRAY['Define professional boundaries in a home care context','Recognise the early signs of caregiver burnout','Apply at least three stress management strategies','Identify Vitalis''s employee support resources','Describe what appropriate and inappropriate caregiver-client relationships look like'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG002-MOD-001', 'PROG-002', 'PROG002-TRK-01', 'Dementia Types, Causes & Progression', 'Alzheimer''s disease, vascular dementia, Lewy body, frontotemporal dementia. Stages of progression, what changes to expect, and how each type affects daily care.', 'mandatory', 1, 50, ARRAY['Distinguish between Alzheimer''s disease and other common dementia types','Describe the three stages of Alzheimer''s progression and their care implications','Identify early warning signs that dementia may be progressing','Explain why dementia is not a normal part of ageing','Adapt care approach to match the client''s current stage'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG002-MOD-002', 'PROG-002', 'PROG002-TRK-01', 'Communication Strategies for Dementia Care', 'Verbal and non-verbal communication adapted for dementia. Therapeutic fibbing, validation therapy, avoiding confrontation, maintaining connection.', 'mandatory', 2, 45, ARRAY['Apply validation therapy principles in client interactions','Use non-confrontational communication techniques','Understand when and how to use therapeutic fibbing ethically','Maintain meaningful communication as verbal ability declines','Interpret non-verbal cues from clients who cannot express themselves verbally'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG002-MOD-003', 'PROG-002', 'PROG002-TRK-02', 'Behavioural Symptoms & De-escalation', 'Agitation, sundowning, aggression, repetitive behaviours, paranoia. Identifying triggers, de-escalation techniques, redirection, and when to call for help.', 'mandatory', 1, 50, ARRAY['Identify the most common behavioural symptoms of dementia','Recognise environmental and physiological triggers for behavioural episodes','Apply at least four de-escalation techniques safely','Use redirection effectively without causing distress','Know when a behavioural episode requires supervisor or emergency intervention'], 'LMS', '#A32D2D', 'draft', 80),
  ('PROG002-MOD-004', 'PROG-002', 'PROG002-TRK-02', 'Wandering Prevention & Home Safety', 'Why clients with dementia wander, environmental modifications, supervision strategies, emergency response if a client goes missing.', 'mandatory', 2, 40, ARRAY['Explain why wandering occurs in dementia clients','Identify home modifications that reduce wandering risk','Apply structured activity and routine to reduce wandering episodes','Execute the correct procedure if a client with dementia goes missing','Use the Safe Return programme and similar resources appropriately'], 'LMS', '#A32D2D', 'draft', 80),
  ('PROG002-MOD-005', 'PROG-002', 'PROG002-TRK-03', 'Meaningful Activities & Engagement', 'Adapting activities to cognitive ability, using music and reminiscence therapy, maintaining purpose and connection, sensory stimulation.', 'core', 1, 40, ARRAY['Select activities matched to a client''s current cognitive stage','Use music and reminiscence to improve mood and engagement','Apply sensory stimulation approaches for late-stage dementia','Create simple structured routines that reduce anxiety','Document activity engagement and client response accurately'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG002-MOD-006', 'PROG-002', 'PROG002-TRK-03', 'Supporting Families & Caregiver Wellbeing', 'Family grief and stress, how caregivers can support families without overstepping, dementia caregiver burnout, self-care strategies.', 'skill_building', 2, 35, ARRAY['Recognise signs of caregiver stress in family members','Communicate with family members in a supportive, professional manner','Set appropriate boundaries when family requests conflict with the Plan of Care','Identify and use Vitalis support resources for caregiver wellbeing','Apply self-care strategies specific to dementia care settings'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG002-MOD-007', 'PROG-002', 'PROG002-TRK-03', 'End-of-Life Care in Dementia', 'Recognising end-of-life changes in dementia clients, comfort-focused care, communicating with families, MOLST awareness, emotional support.', 'skill_building', 3, 35, ARRAY['Identify physical signs that a dementia client may be approaching end of life','Apply comfort-focused care techniques in late-stage dementia','Understand the role of MOLST in Maryland end-of-life decisions','Communicate compassionately with families during this period','Manage personal emotional responses to client decline and death'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG003-MOD-001', 'PROG-003', 'PROG003-TRK-01', 'Understanding the Autism Spectrum', 'What autism is and is not, the spectrum concept, strengths-based framing, identity-first vs person-first language, neurodiversity perspective.', 'mandatory', 1, 50, ARRAY['Define autism spectrum disorder using accurate, strengths-based language','Explain what the spectrum means in terms of individual variation','Use identity-first and person-first language appropriately and sensitively','Distinguish between myths and evidence-based facts about autism','Apply a neurodiversity perspective to caregiver practice'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG003-MOD-002', 'PROG-003', 'PROG003-TRK-01', 'Sensory Processing & Environment', 'Hyper and hypo-sensitivities, sensory triggers, environmental modifications, sensory regulation strategies, creating a calm care environment.', 'mandatory', 2, 45, ARRAY['Distinguish between hypersensitivity and hyposensitivity to sensory input','Identify common sensory triggers in home care environments','Modify the care environment to reduce sensory overwhelm','Apply sensory regulation strategies during care interactions','Recognise when sensory overload is occurring and respond appropriately'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG003-MOD-003', 'PROG-003', 'PROG003-TRK-02', 'Communication Approaches & AAC', 'Augmentative and Alternative Communication (AAC), PECS, visual schedules, social stories, supporting non-verbal and minimally verbal children.', 'mandatory', 1, 50, ARRAY['Define AAC and identify the main types used with autistic children','Support a child who uses a PECS system during care interactions','Use visual schedules to reduce transition anxiety','Communicate effectively with non-verbal and minimally verbal children','Create simple social stories to prepare a child for a care activity'], 'LMS', '#185FA5', 'draft', 80),
  ('PROG003-MOD-004', 'PROG-003', 'PROG003-TRK-02', 'Behavioural Support & Crisis Prevention', 'Understanding behaviour as communication, meltdown vs shutdown, antecedent-behaviour-consequence (ABC) model, crisis prevention and de-escalation.', 'mandatory', 2, 50, ARRAY['Interpret challenging behaviour as communication rather than defiance','Distinguish between a meltdown and a shutdown and respond appropriately to each','Apply the ABC model to identify triggers for behavioural episodes','Use proactive strategies to prevent crisis situations','De-escalate a crisis situation safely without restraint'], 'LMS', '#185FA5', 'draft', 80),
  ('PROG003-MOD-005', 'PROG-003', 'PROG003-TRK-03', 'Supporting Daily Living Skills', 'ADL support for autistic children — bathing, dressing, mealtimes, sleep routines. Task analysis, chaining, positive reinforcement, consistency.', 'core', 1, 40, ARRAY['Break down ADL tasks using task analysis for autistic children','Apply forward or backward chaining to teach self-care steps','Use positive reinforcement consistently during care routines','Support children with eating challenges, food sensitivities, and mealtime routines','Maintain consistent routines that reduce anxiety during daily care'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG003-MOD-006', 'PROG-003', 'PROG003-TRK-03', 'Working with Families & Care Teams', 'Parent-caregiver partnership, IEP awareness, multi-disciplinary team communication, consistency across settings, self-care for caregivers.', 'skill_building', 2, 35, ARRAY['Build a respectful, collaborative relationship with the child''s family','Understand the role of the IEP and how it informs home care','Communicate effectively with schools, therapists, and other care team members','Maintain consistency with strategies used in other settings','Manage the emotional demands of paediatric disability care'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG004-MOD-001', 'PROG-004', 'PROG004-TRK-01', 'Understanding Developmental Disabilities', 'Definition and types of IDD (Down syndrome, cerebral palsy, intellectual disability, fragile X, etc.), causes, prevalence, and how IDD differs from acquired disability.', 'mandatory', 1, 50, ARRAY['Define intellectual and developmental disability using current, respectful terminology','Identify the most common types of developmental disability encountered in home care','Distinguish IDD from acquired disability and mental illness','Apply a strengths-based, person-centred perspective to IDD care','Avoid common myths and stereotypes about people with developmental disabilities'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG004-MOD-002', 'PROG-004', 'PROG004-TRK-01', 'Rights, Advocacy & Dignity', 'Rights of people with IDD, the HCBS Settings Rule, self-determination, supported decision-making, guardianship basics, abuse prevention.', 'mandatory', 2, 45, ARRAY['State the core rights of individuals with developmental disabilities under Maryland and federal law','Explain the CMS HCBS Settings Rule and how it affects home care practice','Support client self-determination within safe boundaries','Distinguish between supported decision-making and guardianship','Recognise and respond to signs of abuse, neglect, or exploitation in IDD clients'], 'LMS', '#534AB7', 'draft', 80),
  ('PROG004-MOD-003', 'PROG-004', 'PROG004-TRK-02', 'Person-Centred Care Planning', 'What person-centred planning is, reading and following an Individual Support Plan (ISP), adapting care to the individual, goal support.', 'mandatory', 1, 45, ARRAY['Define person-centred planning and its principles','Read and interpret an Individual Support Plan (ISP)','Adapt daily care to align with the client''s ISP goals','Support skill-building goals without promoting dependency','Document goal progress accurately and objectively'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG004-MOD-004', 'PROG-004', 'PROG004-TRK-02', 'Daily Living Skills Support for IDD', 'Prompting hierarchies, task analysis, positive behaviour support, community integration, adaptive equipment, hygiene and self-care support.', 'core', 2, 45, ARRAY['Apply a least-to-most prompting hierarchy in daily care tasks','Break down complex tasks using task analysis','Use positive behaviour support strategies consistently','Support community integration within the scope of the care plan','Identify and use adaptive equipment safely and appropriately'], 'LMS', '#0F6E56', 'draft', 80),
  ('PROG004-MOD-005', 'PROG-004', 'PROG004-TRK-03', 'Health Monitoring & Common Health Conditions in IDD', 'Health conditions common in IDD (epilepsy, dysphagia, co-occurring mental health), medication awareness, health monitoring, when to escalate.', 'mandatory', 1, 45, ARRAY['Identify health conditions that are more prevalent in people with IDD','Recognise a seizure and respond correctly using the seizure action plan','Apply dysphagia precautions during mealtimes','Monitor health changes and document them accurately','Distinguish between situations requiring immediate emergency response and routine escalation'], 'LMS', '#A32D2D', 'draft', 80),
  ('PROG004-MOD-006', 'PROG-004', 'PROG004-TRK-03', 'Working with Families, Teams & the DDA System', 'Family dynamics in IDD care, Maryland DDA system overview, multi-disciplinary team roles, advocating for the client, caregiver sustainability.', 'skill_building', 2, 35, ARRAY['Navigate family dynamics respectfully in IDD home care','Understand the role of the Maryland Developmental Disabilities Administration (DDA)','Communicate effectively with the client''s wider support team','Advocate for the client''s needs and preferences within appropriate boundaries','Sustain personal wellbeing while providing IDD care long-term'], 'LMS', '#A32D2D', 'draft', 80)
